    {
      "path": "package.json",
      "content": "{
  "name": "node-project",
  "version": "1.0.0",
  "description": "A simple Node.js project with Express",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js",
    "test": "echo \"Error: no test specified\" && exit 1"
  },
  "dependencies": {
    "express": "^4.17.3"
  },
  "devDependencies": {
    "supertest": "^6.2.4"
  }
}
