    {
      "path": "src/lib/errors.js",
      "content": "function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}

module.exports = { sendError };
"
    },
    {
      "path": "src/lib/id.js",
      "content": "const { randomUUID } = require('node:crypto');

function generateId() {
  return randomUUID();
}

module.exports = { generateId };
"
    },
    {
      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name || typeof name !== 'string' || name.trim() === '') {
    return sendError(res, 400, 'INVALID_NAME', 'Name must be a non-empty string');
  }

  try {
    const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;
"
    },
    {
      "path": "src/modules/projects/service.js",
      "content": "const { generateId } = require('../../lib/id');

let projectsStore = [];

async function getAllProjects() {
  return projectsStore;
}

async function createProject(name) {
  const project = {
    id: generateId(),
    name,
  };
  projectsStore.push(project);
  return project;
}

module.exports = { getAllProjects, createProject };
"
