    {
      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const projectId = req.params.projectId;
  const status = req.query.status;

  try {
    const tasks = await tasksService.getTasksByProject(projectId);
    if (status === 'done') {
      const doneTasks = tasks.filter(task => task.status === 'done');
      res.json({ tasks: doneTasks });
    } else {
      res.json({ tasks });
    }
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const projectId = req.params.projectId;
  const { title } = req.body;

  if (!title || typeof title !== 'string' || title.trim() === '') {
    return sendError(res, 400, 'INVALID_TITLE', 'Title must be a non-empty string');
  }

  try {
    const task = await tasksService.createTask(projectId, title);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;
"
    },
    {
      "path": "src/modules/tasks/service.js",
      "content": "const { generateId } = require('../../lib/id');

let tasksStore = [];

async function getTasksByProject(projectId) {
  return tasksStore.filter(task => task.projectId === projectId);
}

async function createTask(projectId, title) {
  const task = {
    id: generateId(),
    projectId,
    title,
    status: 'todo',
  };
  tasksStore.push(task);
  return task;
}

module.exports = { getTasksByProject, createTask };
"
