      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const projectId = req.params.projectId;

  try {
    const members = await membersService.getMembersByProject(projectId);
    res.json({ members });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const projectId = req.params.projectId;
  const { userId, role } = req.body;

  if (!userId || typeof userId !== 'string' || userId.trim() === '') {
    return sendError(res, 400, 'INVALID_USER_ID', 'User ID must be a non-empty string');
  }

  if (!role || typeof role !== 'string' || role.trim() === '') {
    return sendError(res, 400, 'INVALID_ROLE', 'Role must be a non-empty string');
  }

  try {
    const member = await membersService.addMemberToProject(projectId, userId, role);
    res.status(201).json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;
"
