      "path": "src/modules/comments/routes.js",
      "content": "const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;

  try {
    const comments = await commentsService.getCommentsByTask(projectId, taskId);
    res.json({ comments });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { content } = req.body;

  if (!content || typeof content !== 'string' || content.trim() === '') {
    return sendError(res, 400, 'INVALID_CONTENT', 'Content must be a non-empty string');
  }

  try {
    const comment = await commentsService.addCommentToTask(projectId, taskId, content);
    res.status(201).json({ comment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;
"
