      "path": "src/modules/comments/service.js",
      "content": "const { generateId } = require('../../lib/id');

let commentsStore = [];

async function getCommentsByTask(projectId, taskId) {
  return commentsStore.filter(comment => comment.projectId === projectId && comment.taskId === taskId);
}

async function addCommentToTask(projectId, taskId, content) {
  const comment = {
    id: generateId(),
    projectId,
    taskId,
    content,
  };
  commentsStore.push(comment);
  return comment;
}

module.exports = { getCommentsByTask, addCommentToTask };
